import{H as e,V as t,et as n,j as r}from"./chunks/framework.C_EfTa_6.js";import"./chunks/assets.BcOnMUHA.js";var i=JSON.parse(`{"title":"消费级","description":"","frontmatter":{"title":"消费级","order":10},"headers":[],"relativePath":"kernel/equip/motherboard/consumer.md","filePath":"kernel/equip/motherboard/consumer.md"}`),a={name:`kernel/equip/motherboard/consumer.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="消费级主板" tabindex="-1">消费级主板 <a class="header-anchor" href="#消费级主板" aria-label="Permalink to “消费级主板”">​</a></h1><p>消费级主板主要面向游戏场景和个人 PC，搭载一个 x16 的显卡 PCIe 插槽并且支持 CPU 直连，强调单核性能、超频能力和性价比。与之相对的企业级主板强调可扩展性和可靠性，具有较多的内存插槽（通常 8~24 条 DIMM）和 PCIe 插槽（通常 4~10 条），且全部支持 ECC 内存和远程带外管理（BMC/IPMI）。</p><h2 id="主板常见参数" tabindex="-1">主板常见参数 <a class="header-anchor" href="#主板常见参数" aria-label="Permalink to “主板常见参数”">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>核心含义</th><th>为什么关注</th></tr></thead><tbody><tr><td>CPU 插座（Socket）</td><td>物理接口</td><td>插座不匹配 = 无法安装 CPU</td></tr><tr><td>供电相数（VRM）</td><td>CPU 供电模块</td><td>超频/高功耗 CPU 稳定性</td></tr><tr><td>芯片组（Chipset）</td><td>决定 CPU 支持、PCIe 通道、超频能力</td><td>错芯片组 = CPU 装不上；高端芯片组解锁更多 PCIe/M.2</td></tr><tr><td>内存支持</td><td>类型/频率/通道/容量</td><td>影响多任务、游戏帧数；DDR5 已主流</td></tr><tr><td>PCIe 插槽</td><td>版本 × 通道数</td><td>显卡/SSD/扩展卡带宽瓶颈</td></tr><tr><td>M.2 插槽</td><td>SSD 接口数量/规格</td><td>系统盘+游戏盘速度</td></tr><tr><td>后置 I/O</td><td>USB/网口/音频</td><td>外设连接</td></tr><tr><td>扩展槽</td><td>SATA/PCIe 小槽</td><td>机械硬盘/声卡/采集卡</td></tr><tr><td>BIOS 功能</td><td>超频/调试</td><td>后期优化</td></tr><tr><td>尺寸/布局</td><td>Form Factor</td><td>机箱兼容 + 走线</td></tr></tbody></table><h2 id="cpu-适配性" tabindex="-1">CPU 适配性 <a class="header-anchor" href="#cpu-适配性" aria-label="Permalink to “CPU 适配性”">​</a></h2><p>主板的型号首先受限于 CPU，不同的 CPU 需要使用的主板互不相同。因此，Intel CPU 和 AMD CPU 必须使用完全不同的主板，不能混用，选择主板时，应该先选择 CPU。</p><ol><li>插座，不同的 CPU 使用不同的插座，即使是同一个公司的不同的 CPU 插座也不一定相同。AMD 的插槽一般是 AM5，intel 的插槽一般是 LGA 1700。</li><li>CPU 插座选择：AMD 的插槽一般是 AM5，intel 的插槽一般是 LGA 1700。同一品牌的不同代 CPU 插座也不一定相同，选购时要确认主板插座与 CPU 匹配。</li></ol><h3 id="供电相数与-vrm" tabindex="-1">供电相数与 VRM <a class="header-anchor" href="#供电相数与-vrm" aria-label="Permalink to “供电相数与 VRM”">​</a></h3><p>VRM（Voltage Regulator Module）将电源的 12V 直流电降压转换为 CPU 核心所需的约 0.8-1.4V 低压大电流。CPU 满载时电流可达 200-400A，单相供电无法承受——这就是 VRM 采用多相交替供电的原因。</p><p>每一相供电由三个核心元件组成：PWM 控制器（产生控制信号）、DrMOS（集成驱动 IC + 上桥 MOSFET + 下桥 MOSFET，负责实际的电流开关）、以及电感 + 电容（滤波储能，将开关方波平滑为 CPU 可用的直流电）。多相 VRM 将各相的输出波形错开——8 相就是 8 路电流以 360°/8 = 45° 的相位差交替输出，叠加后的总波形纹波远小于单相，等效开关频率是单相的 8 倍。</p><p>供电相的标称值有时有误导性。主板厂商常标&quot;16+2+1 相&quot;——16 相给 CPU 核心（Vcore）、2 相给 SOC/IO Die（VDD_SOC）、1 相给集显。但某些主板用倍相器（Phase Doubler）将一个 PWM 通道拆为两相——称之为&quot;8+8&quot;的两相实际来自同一个 PWM 信号，电气特性不如真正的独立 16 相。最简单的判据：PWM 控制器的型号有多少个独立通道，乘以每通道是否配了独立的 DrMOS 即可得出真实供电能力。</p><p>实际选购中，供电相数是否重要取决于 CPU 功耗。满载 65W 的 CPU（如 Ryzen 5 7600）用 B650 丐板的 6-8 相供电完全足够，供电温度不过 60°C。满载 250W 的 CPU（如 14900K 不设功耗墙）需要至少 12 相以上优质 VRM——此时判断 VRM 能力的指标不是相数而是相数 × 每相电流能力。每相 50A 的 12 相 DrMOS 总供电 600A，可以稳定支撑 250W CPU + 瞬时峰值负载。</p><p>VRM 散热也同样重要。供电相在高负载下会发热——每相 50A 效率约 90% 时，12 相满载的散热功率约 60-80W，需要足够散热片面积的覆盖。裸 MOSFET（无散热片覆盖）在高负载下可超过 100°C 并触发 VRM 过热降频，直接表现就是 CPU 跑一会儿频率骤降——这不是 CPU 降频，是供电扛不住了。选购时看一下 VRM 散热片是否真正接触 MOSFET 而不只是盖在电感上——只散热电感不散热 MOSFET 的装饰性散热片在高负载下完全没有效果。</p><h3 id="功耗预估与相数计算" tabindex="-1">功耗预估与相数计算 <a class="header-anchor" href="#功耗预估与相数计算" aria-label="Permalink to “功耗预估与相数计算”">​</a></h3><p>以 240W TDP CPU + 8 条 DDR4 DIMM 的配置为例，逐步计算供电需求。</p><p>CPU Vcore 是供电的大头。TDP 是持续热设计功耗而非实际峰值功耗——Intel 的 PL2（Turbo Boost Power Max）通常是 TDP 的 1.5-2 倍，AMD 的 PPT（Package Power Tracking）通常比 TDP 高 30-50%。一个 240W TDP 的 CPU，PL2/PPT 通常在 300-360W。供电设计应取实际可能的最大值而非 TDP——建议用 TDP × 1.5 作为 Vcore 供电的预估值。240W × 1.5 = 360W。</p><p>SOC/IO Die 的功耗源于内存控制器和互联总线。DDR4 满载时每条 DIMM 约 3-5W（取决于频率和 rank 数），8 条 DIMM 的满载功耗约为 24-40W（内存颗粒本身的功耗由 PSU 直接提供，但内存控制器消耗的电流走 VDD_SOC 供电轨）。此外还有 Infinity Fabric、PCIe 根复合体等 IO 功耗（约 15-25W）。VDD_SOC 供电的预估值约为 40-65W。</p><p>Vcore + VDD_SOC 的合计峰值功耗约为 360 + 65 = 425W。设 VRM 转换效率为 90%，则输入功率约为 425 / 0.9 = 472W，VRM 本身发热约 47W。</p><p>相数需求取决于每相的电流能力和降额设计。常见的 DrMOS 分三个等级：</p><table tabindex="0"><thead><tr><th>等级</th><th>单相电流</th><th>典型 DrMOS</th><th>使用场景</th></tr></thead><tbody><tr><td>入门</td><td>40-50A</td><td>Vishay SiC639 / ON NCP302045</td><td>B 系列丐板</td></tr><tr><td>中端</td><td>60-70A</td><td>Renesas ISL99360 / MPS MP86956</td><td>B650 中高端 / Z790</td></tr><tr><td>高端</td><td>90-110A</td><td>Infineon TDA21490 / Renesas ISL99390</td><td>X670E 旗舰 / Z890</td></tr></tbody></table><p>实际可用电流要打 70-80% 的降额——标称 50A 的 DrMOS 长期稳定工作电流约 35-40A（持续满载下温度可能超过 100°C 且效率下降）。CPU 核心电压约 1.2V 时，单相 50A DrMOS 的实际供电能力为 1.2V × 50A × 75% = 45W。</p><p>因此 425W 峰值功耗需要的相数为 425 / 45 = 9.4 相，取整为 10 相 Vcore。注意这不是主板标称相数的 10 相——如果使用倍相器，10 个&quot;标称相&quot;可能只有 5 个真正的 PWM 通道，每通道 2 相的瞬时响应不如真正的 10 相独立供电。所以结论是：240W CPU + 8 DDR4 需要至少 <strong>12 相独立（非倍相）的 Vcore DrMOS 每相 ≥ 50A</strong>，加上 2-3 相 VDD_SOC 供电。</p><p>常见主板是否达标可以用这个公式快速验算。一块&quot;8+2+1 相、每相 50A&quot;的主板，Vcore 共 8 相 × 50A × 75% × 1.2V = 360W——裸测下能勉强拖 240W CPU（360W &gt; 360W 理论需求）但没有余量，一旦主板散热风道不够好 VRM 就会过热降频。升级到&quot;12+2+1 相、每相 50A&quot;就是 540W 理论能力——富余量足够 VRM 温度控制在安全范围内。</p><h2 id="芯片组" tabindex="-1">芯片组 <a class="header-anchor" href="#芯片组" aria-label="Permalink to “芯片组”">​</a></h2><p>也称为南桥（Platform Controller Hub），总管计算机的外设。芯片组通过扩展总线通道和 CPU 进行交互，区分于 CPU 的直连通道。</p><p>对于 intel 来说，扩展总线通道使用了一种专用的总线协议 DMI 总线，而 AMD 则依旧使用的是 PCIe 通道</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>   ┌──────────────┐</span></span>
<span class="line"><span>   │    CPU       │</span></span>
<span class="line"><span>   │  ├──16× PCIe5 GPU</span></span>
<span class="line"><span>   │  ├──4×  PCIe4 NVMe</span></span>
<span class="line"><span>   │  └─── DMI4.0 x8 ─────┐</span></span>
<span class="line"><span>   └──────────────┘        │</span></span>
<span class="line"><span>                            ▼</span></span>
<span class="line"><span>                  ┌───────────────────┐</span></span>
<span class="line"><span>                  │       PCH         │</span></span>
<span class="line"><span>                  │ USB / SATA / PCIe │</span></span>
<span class="line"><span>                  │ 网卡 / 声卡等控制器 │</span></span>
<span class="line"><span>                  └───────────────────┘</span></span></code></pre></div><h2 id="插槽形状" tabindex="-1">插槽形状 <a class="header-anchor" href="#插槽形状" aria-label="Permalink to “插槽形状”">​</a></h2><p>在目前的消费级 PC 主板上，有不同类型的外设插槽类型。</p><blockquote><p>注意 CPU 使用 CPU 插槽，内存使用 DDR 插槽。一般的消费级主板，CPU 插槽是 1 个，内存插槽是 4 个。</p></blockquote><h3 id="pcie-插槽" tabindex="-1">PCIe 插槽 <a class="header-anchor" href="#pcie-插槽" aria-label="Permalink to “PCIe 插槽”">​</a></h3><p>单个 PCIe5 的通道带宽是 4GiB/s，单个 PCIe4 的通道带宽是 2GiB/s。一些设备的带宽要求较高，可以将多个通道进行合并，从而被同一个设备所使用。接口形似一个钥匙。</p><p><img src="/assets/pcie.D4Y8bg-y.avif" alt="PCIe 插槽转换器" width="515" height="570"></p><p>典型的通道合并规格有：</p><ul><li>x1：网卡、声卡、WiFi 卡</li><li>x4：NVMe SSD 硬盘、Thunderbolt 卡、10G 网卡</li><li>x8：双卡桥接、AI 加速卡</li><li>x16：显卡、高性能计算卡</li></ul><p>常见的 PCIe 设备</p><table tabindex="0"><thead><tr><th>设备类型</th><th>推荐规格</th><th>带宽需求</th><th>示例产品</th></tr></thead><tbody><tr><td>GPU</td><td>x16</td><td>≥32 GiB/s</td><td>RTX 4090 / 5090</td></tr><tr><td>NVMe SSD</td><td>x4</td><td>8-16 GiB/s</td><td>三星 990 PRO (Gen4) / 致态 TiPro9000 (Gen5)</td></tr><tr><td>10G/25G 网卡</td><td>x4</td><td>≥5 GiB/s</td><td>Mellanox ConnectX-6</td></tr><tr><td>Thunderbolt 卡</td><td>x4</td><td>5 GiB/s</td><td>华硕 ThunderboltEX 4</td></tr><tr><td>WiFi 卡</td><td>x1</td><td>&lt;1 GiB/s</td><td>Intel BE200</td></tr><tr><td>RAID 扩展卡</td><td>x4/x8</td><td>10-30 GiB/s</td><td>华硕 Hyper M.2 x16</td></tr><tr><td>专业采集卡</td><td>x8/x16</td><td>20+ GiB/s</td><td>Blackmagic DeckLink 8K</td></tr></tbody></table><h3 id="m-2-插槽" tabindex="-1">M.2 插槽 <a class="header-anchor" href="#m-2-插槽" aria-label="Permalink to “M.2 插槽”">​</a></h3><p>常见的使用 M.2 插槽的设备，有 NVMe SSD 硬盘，下层使用的可以是 PCIe 总线协议、SATA 协议、USB 协议</p><p><img src="/assets/ssd.DxKz2m2l.avif" alt="固态硬盘" width="720" height="566"></p><p>插槽形态差异（Key Type），M.2 接口有不同的&quot;缺口（Key）&quot;设计，用来防止错误插入：</p><ul><li>M Key：用于 NVMe SSD，支持 PCIe x4。</li><li>B Key：用于 SATA/PCIe x2/USB。</li><li>B+M Key：混合型 SSD，能在 B 或 M 插槽上都插。</li></ul><p><img src="/assets/m_2.BHqkZSD_.png" alt="" width="807" height="351"></p><h3 id="sata-接口" tabindex="-1">SATA 接口 <a class="header-anchor" href="#sata-接口" aria-label="Permalink to “SATA 接口”">​</a></h3><p>主要用于老式的机械硬盘，形状形如 L 形。</p><h3 id="io-背板" tabindex="-1">IO 背板 <a class="header-anchor" href="#io-背板" aria-label="Permalink to “IO 背板”">​</a></h3><p>位于主板背面边缘，插入机箱后对应机箱后面板的开口。通常是一块长条形金属区域，有很多接口孔，用于外接各种设备。</p><ul><li>音频接口，3.5mm 音频口（Line-out、Mic-in、Line-in），有些高端板带 光纤输出（S/PDIF）</li><li>USB 接口，USB 2.0 / 3.0 / 3.1 / 3.2，有的板上还有 USB-C 接口</li><li>网络接口（LAN），RJ45 网口，可能是 1G/2.5G/10G，高端板可能还有双网口或光纤接口</li><li>视频输出接口（仅 CPU 带集显或板载显卡时有），HDMI、DisplayPort、VGA</li><li>PS/2 接口，有些板还保留老式键盘/鼠标接口</li><li>Wi-Fi / 蓝牙天线接口（天线螺母接口）</li></ul><h3 id="其他插槽" tabindex="-1">其他插槽 <a class="header-anchor" href="#其他插槽" aria-label="Permalink to “其他插槽”">​</a></h3><table tabindex="0"><thead><tr><th>插槽名称</th><th>形状描述</th><th>尺寸/针脚</th><th>用途</th><th>位置</th><th>示例设备</th></tr></thead><tbody><tr><td>前置面板头</td><td>小针脚阵列（2x5 或 2x10）</td><td>9-19 针</td><td>接机箱按钮/灯</td><td>主板右下</td><td>Power SW / HDD LED</td></tr><tr><td>ARGB / RGB 头</td><td>小 3/4 针排针</td><td>3 针 (RGB) / 4 针 (ARGB)</td><td>接灯条</td><td>主板边缘</td><td>风扇/灯带</td></tr><tr><td>Thunderbolt 头</td><td>5 针小排针</td><td>5 针</td><td>接 TB 扩展卡</td><td>主板下</td><td>华硕 TBEX 4</td></tr><tr><td>COM 串口头</td><td>9 针排针</td><td>9 针</td><td>老设备调试</td><td>主板后 I/O</td><td>工业串口</td></tr><tr><td>TPM 头</td><td>2x7 或 2x10 排针</td><td>14/20 针</td><td>安全模块</td><td>主板下</td><td>TPM 2.0 模块</td></tr><tr><td>扇热头</td><td>小 3/4 针口</td><td>3 针 (DC) / 4 针 (PWM)</td><td>接风扇/水泵</td><td>主板四周</td><td>240 水冷泵</td></tr><tr><td>ATX 电源头</td><td>大方块排针</td><td>24 针主 + 8 针 CPU</td><td>供电</td><td>主板右上</td><td>海盗船 RM850x</td></tr><tr><td>PCIe 电源头</td><td>6/8 针方块</td><td>6+2 针</td><td>给 GPU 供电</td><td>主板右</td><td>RTX 4090 12VHPWR</td></tr></tbody></table><h2 id="常见主板型号" tabindex="-1">常见主板型号 <a class="header-anchor" href="#常见主板型号" aria-label="Permalink to “常见主板型号”">​</a></h2><p>PCIe 通道决定显卡安装的数量；M.2 决定了硬盘安装的数量。</p><p>主板和 CPU 一般相适应，并且分为消费级、专业级和企业级，分为对应个人 PC、工作室的工作站、企业的服务器。</p><h3 id="intel-主板" tabindex="-1">intel 主板 <a class="header-anchor" href="#intel-主板" aria-label="Permalink to “intel 主板”">​</a></h3><p>intel 的 CPU 分为</p><ul><li>intel Core</li><li>intel Xeon</li></ul><table tabindex="0"><thead><tr><th>芯片组</th><th>定位</th><th>超频支持</th><th>插槽</th><th>pcie</th></tr></thead><tbody><tr><td>Z890</td><td>发烧/超频</td><td>CPU + 内存</td><td>LGA 1851</td><td>PCIe 5.0</td></tr><tr><td>Z790</td><td>发烧/超频</td><td>CPU + 内存</td><td>LGA 1700</td><td>PCIe 5.0</td></tr><tr><td>Z690</td><td>上代旗舰</td><td>CPU + 内存</td><td>LGA 1700</td><td>PCIe 5.0</td></tr><tr><td>H810</td><td>入门/稳定</td><td>否</td><td>LGA 1851</td><td>PCIe 4.0</td></tr><tr><td>H770</td><td>企业/稳定</td><td>否</td><td>LGA 1700</td><td>PCIe 4.0</td></tr><tr><td>B860</td><td>中端</td><td>内存</td><td>LGA 1851</td><td>PCIe 5.0</td></tr><tr><td>B760</td><td>主流性价比</td><td>内存</td><td>LGA 1700</td><td>PCIe 4.0</td></tr></tbody></table><blockquote><p>Z 高端/旗舰，Q 企业/商务，H 主流，B 入门，M 体积小但扩展性阉割 第一位数字，代际，第二位数字，级别 LGA 1851 对应 800 系（Core Ultra），LGA 1700 对应 600/700 系（12-14 代 Core）；CPU 直连通道均为 PCIe 5.0，但 B760/H 系列主板常把显卡插槽降配为 PCIe 4.0 以节省成本</p></blockquote><h3 id="amd-主板" tabindex="-1">AMD 主板 <a class="header-anchor" href="#amd-主板" aria-label="Permalink to “AMD 主板”">​</a></h3><p>AMD 的 CPU 分为</p><ul><li>Ryzen</li><li>Threadripper</li><li>EPYC</li></ul><h4 id="消费级" tabindex="-1">消费级 <a class="header-anchor" href="#消费级" aria-label="Permalink to “消费级”">​</a></h4><blockquote><p>AMD 芯片组命名规则：X 高端，B 主流，A 入门，E 后缀表示扩展性增强。第一位数字代表代际，第二位数字代表级别。</p></blockquote><p><strong>AM5 平台（当前，2022-）</strong></p><p>AM5 平台使用 LGA 1718 插座，支持 DDR5 内存和 PCIe 5.0，对应 Ryzen 7000/9000 系列 CPU。</p><table tabindex="0"><thead><tr><th>芯片组</th><th>定位</th><th>超频支持</th><th>插槽</th><th>pcie</th></tr></thead><tbody><tr><td>X870E</td><td>旗舰/发烧</td><td>是</td><td>AM5</td><td>PCIe 5.0</td></tr><tr><td>X870</td><td>高端</td><td>是</td><td>AM5</td><td>PCIe 5.0</td></tr><tr><td>B850</td><td>中高端</td><td>是</td><td>AM5</td><td>PCIe 5.0</td></tr><tr><td>B840</td><td>主流</td><td>否</td><td>AM5</td><td>PCIe 4.0</td></tr><tr><td>X670E</td><td>旗舰/发烧</td><td>是</td><td>AM5</td><td>PCIe 5.0</td></tr><tr><td>X670</td><td>高端</td><td>是</td><td>AM5</td><td>PCIe 5.0</td></tr><tr><td>B650E</td><td>中高端</td><td>是</td><td>AM5</td><td>PCIe 5.0</td></tr><tr><td>B650</td><td>主流甜点</td><td>是</td><td>AM5</td><td>PCIe 4.0</td></tr><tr><td>A620</td><td>入门</td><td>否</td><td>AM5</td><td>PCIe 4.0</td></tr></tbody></table><blockquote><p>E 后缀（X670E/B650E）保证显卡插槽为 PCIe 5.0，无 E 的 B650 显卡槽多为 PCIe 4.0；B840/A620 则直接把 CPU 直连通道限制在 PCIe 4.0</p></blockquote><p><strong>AM4 平台（上一代，2016-2022）</strong></p><p>AM4 是 AMD 历史上生命周期最长的消费级平台，使用 PGA 1331 插座，横跨 Zen 1 到 Zen 3 四代架构（Ryzen 1000/2000/3000/5000 系列），全部使用 DDR4 内存。</p><table tabindex="0"><thead><tr><th>芯片组</th><th>定位</th><th>超频支持</th><th>插槽</th><th>pcie</th></tr></thead><tbody><tr><td>X570</td><td>旗舰/发烧</td><td>是</td><td>AM4</td><td>PCIe 4.0</td></tr><tr><td>B550</td><td>主流甜点</td><td>是</td><td>AM4</td><td>PCIe 4.0</td></tr><tr><td>X470</td><td>上代旗舰</td><td>是</td><td>AM4</td><td>PCIe 3.0</td></tr><tr><td>B450</td><td>主流性价比</td><td>是</td><td>AM4</td><td>PCIe 3.0</td></tr><tr><td>X370</td><td>初代旗舰</td><td>是</td><td>AM4</td><td>PCIe 3.0</td></tr><tr><td>B350</td><td>初代主流</td><td>是</td><td>AM4</td><td>PCIe 3.0</td></tr><tr><td>A520</td><td>入门</td><td>否</td><td>AM4</td><td>PCIe 3.0</td></tr><tr><td>A320</td><td>入门</td><td>否</td><td>AM4</td><td>PCIe 3.0</td></tr></tbody></table><blockquote><p>X570 是唯一芯片组端也支持 PCIe 4.0 的 AM4 平台，通常配有芯片组主动散热风扇；B550 仅 CPU 直连通道（显卡 + 第一个 M.2）支持 PCIe 4.0，芯片组通道为 PCIe 3.0；300/400 系芯片组来自芯片组的 PCIe 通道均为 2.0，A520/A320 不支持 CPU 超频 Ryzen 5000 系列仅 X570/B550/A520 官方原生支持（400 系主板可通过 Beta BIOS 兼容，300 系大多不支持）</p></blockquote><h2 id="内存约束" tabindex="-1">内存约束 <a class="header-anchor" href="#内存约束" aria-label="Permalink to “内存约束”">​</a></h2><p>消费级平台的内存配置细节——包括 DIMM 插槽与通道的关系、QVL 兼容性列表、XMP/EXPO 的本质与风险、DDR 代际的物理隔离——参见 <a href="./ram">主板与内存的适配</a>。</p>`,73)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};